sys_script_include.script:
var IncentNowTransformEngine = Class.create();
IncentNowTransformEngine.prototype = {

    initialize: function () {},

    execute: function (runSysId) {

        var startTime = new GlideDateTime();

        var runGR = this._getRun(runSysId);
        if (!runGR)
            throw "Import Run not found";

        var counters = {
            inserted: 0,
            failed: 0
        };

        var context = this._prepareContext(runGR);
        this._processRows(context, counters);

        this._updateRunMetrics(runGR, counters, startTime);

        return counters;
    },

    /* ===================================================== */

    _getRun: function (runSysId) {

        var runGR = new GlideRecordSecure("x_ctans_incentnow_import_run");
        if (!runGR.get(runSysId))
            return null;

        return runGR;
    },

    /* ===================================================== */

    _prepareContext: function (runGR) {

        var dataModelId = runGR.getValue("data_model_object");

        if (!dataModelId)
            throw "Data model missing";

        var stagingGR = new GlideRecordSecure("x_ctans_incentnow_data_lake_staging");
        stagingGR.addQuery("import_run", runGR.getUniqueValue());
        stagingGR.addQuery("is_valid", true);
        stagingGR.orderBy("row_number");
        stagingGR.query();

        if (!stagingGR.hasNext())
            throw "No valid staging rows found";

        var mappings = this._loadMappings(dataModelId);

        return {
            runSysId: runGR.getUniqueValue(),
            dataModelId: dataModelId,
            stagingGR: stagingGR,
            mappings: mappings
        };
    },

    /* ===================================================== */

    _loadMappings: function (dataModelId) {

        var mappingGR = new GlideRecordSecure("x_ctans_incentnow_metadata_mapping");
        mappingGR.addQuery("data_model_object_id", dataModelId);
        mappingGR.addQuery("active", true);
        mappingGR.query();

        var mappings = [];

        while (mappingGR.next()) {

            mappings.push({
                source: mappingGR.getValue("source_field_name"),
                target: mappingGR.getValue("data_lake_column_name")
            });
        }

        if (mappings.length === 0)
            throw "No metadata mappings configured";

        return mappings;
    },

    /* ===================================================== */

    _processRows: function (context, counters) {

        var stagingGR = context.stagingGR;

        while (stagingGR.next()) {

            try {

                var rowObj = JSON.parse(stagingGR.getValue("raw_json"));

                var targetGR = new GlideRecordSecure("x_ctans_incentnow_data_lake");
                targetGR.initialize();

                /* ===============================
                   SYSTEM CONTROLLED FIELDS
                =============================== */

                targetGR.setValue("data_model_object", context.dataModelId);
                targetGR.setValue("processing_status", "Raw");
                targetGR.setValue("raw_payload", stagingGR.getValue("raw_json"));
                targetGR.setValue("sys_import_set", stagingGR.getValue("sys_import_set"));
                targetGR.setValue("transaction_date", new GlideDateTime());
                targetGR.setValue("user_id", gs.getUserID());
                targetGR.setValue("import_run", context.runSysId);

                /* ===============================
                   DYNAMIC METADATA MAPPING
                =============================== */

                this._applyMappings(targetGR, rowObj, context.mappings);

                targetGR.insert();
                counters.inserted++;

            } catch (rowEx) {

                counters.failed++;
                this._logRowError(context.runSysId, stagingGR, rowEx.toString());
            }
        }
    },

    /* ===================================================== */

    _applyMappings: function (targetGR, rowObj, mappings) {

        for (var i = 0; i < mappings.length; i++) {

            var map = mappings[i];
            var value = rowObj[map.source];

            if (value === undefined || value === null)
                continue;

            targetGR.setValue(map.target, value);
        }
    },

    /* ===================================================== */

    _logRowError: function (runSysId, stagingGR, message) {

        var errGR = new GlideRecordSecure("x_ctans_incentnow_import_error");
        errGR.initialize();
        errGR.setValue("import_run", runSysId);
        errGR.setValue("staging_record", stagingGR.getUniqueValue());
        errGR.setValue("row_number", stagingGR.getValue("row_number"));
        errGR.setValue("error_message", message);
        errGR.setValue("raw_payload", stagingGR.getValue("raw_json"));
        errGR.insert();
    },

    /* ===================================================== */

    _updateRunMetrics: function (runGR, counters, startTime) {

        var endTime = new GlideDateTime();
        var duration = endTime.getNumericValue() - startTime.getNumericValue();

        runGR.setValue("inserted_count", counters.inserted);
        runGR.setValue("updated_count", 0); // Always zero now
        runGR.setValue("failed_count", counters.failed);
        runGR.setValue("execution_time_ms", duration);
        runGR.setValue("status", "Completed");
        runGR.setValue("completed_at", endTime);
        runGR.update();
    },

    type: "IncentNowTransformEngine"
};
